+function sanitizeForTmux(input: string, maxLength: number): string {
+  return (
+    input
+      // Replace path separators and common special chars with hyphen
+      .replace(/[/\\:@#$%^&*()+=\[\]{}|;'"<>,?!`~]/g, "-")
+      // Collapse multiple hyphens
+      .replace(/-+/g, "-")
+      // Remove leading/trailing hyphens
+      .replace(/^-|-$/g, "")
